import sys

class Solution:
    def minDays(self, bloomDay: list[int], m: int, k: int) -> int:
        # If not enough flowers
        if m * k > len(bloomDay):
            return -1
        lo = min(bloomDay)
        hi = max(bloomDay)
        def can_make(days: int) -> bool:
            bouquets = 0
            flowers = 0
            for d in bloomDay:
                if d <= days:
                    flowers += 1
                    if flowers == k:
                        bouquets += 1
                        flowers = 0
                        if bouquets >= m:
                            return True
                else:
                    flowers = 0
            return bouquets >= m
        ans = -1
        while lo <= hi:
            mid = (lo + hi) // 2
            if can_make(mid):
                ans = mid
                hi = mid - 1
            else:
                lo = mid + 1
        return ans

