#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int minDays(vector<int>& bloomDay, int m, int k) {
        long long need = 1LL * m * k;
        if (need > (int)bloomDay.size()) return -1;
        int lo = *min_element(bloomDay.begin(), bloomDay.end());
        int hi = *max_element(bloomDay.begin(), bloomDay.end());
        auto can_make = [&](int days) {
            int bouquets = 0, flowers = 0;
            for (int d : bloomDay) {
                if (d <= days) {
                    ++flowers;
                    if (flowers == k) {
                        ++bouquets;
                        flowers = 0;
                        if (bouquets >= m) return true;
                    }
                } else {
                    flowers = 0;
                }
            }
            return bouquets >= m;
        };
        int ans = -1;
        while (lo <= hi) {
            int mid = lo + (hi - lo) / 2;
            if (can_make(mid)) {
                ans = mid;
                hi = mid - 1;
            } else {
                lo = mid + 1;
            }
        }
        return ans;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> bloomDay(n);
    for (int i = 0; i < n; ++i) cin >> bloomDay[i];
    int m, k;
    if (!(cin >> m >> k)) return 0;
    Solution sol;
    cout << sol.minDays(bloomDay, m, k) << "\n";
    return 0;
}
